import json
import random

# This is a mock of the data that vqasynth would produce.
# In a real scenario, this would be loaded from a file generated by the main pipeline.
# It includes the QA pair and the intermediate metadata used for its generation.
MOCK_SYNTH_DATA = [
    {
        "id": "image001_q1",
        "question": "How far is the red forklift from the brown boxes?",
        "answer": "The red forklift is approximately 7.0 meters away from the brown boxes.",
        "metadata": {
            "objects": {
                "red_forklift": {"bbox": [10, 10, 50, 50], "avg_depth_m": 3.5},
                "brown_boxes": {"bbox": [100, 100, 150, 150], "avg_depth_m": 10.5},
            },
            "scene_context": "warehouse",
        },
    },
    {
        "id": "image001_q2",
        "question": "Is the man in the red hat to the left of the pallet?",
        "answer": "Yes, the man in the red hat is on the left side of the pallet.",
        "metadata": {
            "objects": {
                "man_in_red_hat": {"bbox": [20, 50, 40, 100], "center_x": 30},
                "pallet": {"bbox": [150, 50, 180, 100], "center_x": 165},
            },
            "scene_context": "warehouse",
        },
    },
    {
        "id": "image002_q1",
        "question": "What is the distance between the chair and the table?",
        "answer": "The chair is about 1.2 meters from the table.",
        "metadata": {
            "objects": {
                "chair": {"bbox": [30, 60, 50, 90], "avg_depth_m": 5.8},
                "table": {"bbox": [80, 60, 120, 90], "avg_depth_m": 6.0},
            },
            "scene_context": "office",
        },
    },
]


# --- Inspired by ResearcherBench's Factual Assessment ---
def evaluate_factual_faithfulness(sample, tolerance=0.5):
    """
    Checks if claims in the answer are faithful to the source metadata.
    This is analogous to ResearcherBench's citation/faithfulness check,
    where our "source" is the scene metadata.
    """
    question = sample["question"].lower()
    answer = sample["answer"].lower()
    metadata = sample["metadata"]

    # Check for relative position (left/right)
    if "left of" in question:
        # In a real implementation, object keys would be parsed from the question
        obj1_key, obj2_key = "man_in_red_hat", "pallet"
        if obj1_key in metadata["objects"] and obj2_key in metadata["objects"]:
            obj1_x = metadata["objects"][obj1_key]["center_x"]
            obj2_x = metadata["objects"][obj2_key]["center_x"]
            is_left = obj1_x < obj2_x
            return ("yes" in answer and is_left) or ("no" in answer and not is_left)

    # Check for distance
    if "far" in question or "distance" in question:
        try:
            # Naive parsing of distance from answer string
            answer_dist = float(
                [s for s in answer.split() if s.replace(".", "", 1).isdigit()][0]
            )

            obj_keys = list(metadata["objects"].keys())
            obj1_depth = metadata["objects"][obj_keys[0]]["avg_depth_m"]
            obj2_depth = metadata["objects"][obj_keys[1]]["avg_depth_m"]

            # This is a simplification; real distance requires more geometry
            metadata_dist = abs(obj1_depth - obj2_depth)

            return abs(answer_dist - metadata_dist) <= tolerance
        except (ValueError, IndexError):
            return False  # Could not parse distance from answer

    return None  # Evaluation not applicable


# --- Inspired by ResearcherBench's Rubric Assessment ---
def evaluate_rubric_quality(sample):
    """
    Evaluates the generated sample against a predefined rubric for quality.
    This is analogous to ResearcherBench's expert rubric.
    """
    rubric_scores = {}
    # Rubric Point 1: Is the answer a complete sentence?
    rubric_scores["completeness"] = 1 if sample["answer"].endswith(".") else 0

    # Rubric Point 2: Does the answer contain a colloquial unit?
    has_unit = any(
        unit in sample["answer"] for unit in ["meters", "feet", "meter", "foot"]
    )
    rubric_scores["units_present"] = 1 if has_unit else 0

    return rubric_scores


def main():
    """
    Main function to run the evaluation on the mock data.
    """
    print("Running VQASynth Data Quality Evaluation (inspired by ResearcherBench)")
    print("-" * 70)

    factual_results = []
    rubric_results = []

    for sample in MOCK_SYNTH_DATA:
        is_faithful = evaluate_factual_faithfulness(sample)
        if is_faithful is not None:
            factual_results.append(is_faithful)

        rubric_score = evaluate_rubric_quality(sample)
        rubric_results.append(rubric_score)

    # --- Summarize Results ---
    print("\n--- Factual Faithfulness Summary ---")
    if factual_results:
        faithfulness_score = sum(factual_results) / len(factual_results)
        print(
            f"Faithfulness Score: {faithfulness_score:.2f} ({sum(factual_results)} of {len(factual_results)} samples are faithful to metadata)"
        )
    else:
        print("No applicable samples for factual evaluation.")

    print("\n--- Rubric Quality Summary ---")
    if rubric_results:
        avg_completeness = sum(r["completeness"] for r in rubric_results) / len(
            rubric_results
        )
        avg_units = sum(r["units_present"] for r in rubric_results) / len(
            rubric_results
        )
        print(f"Average Completeness Score: {avg_completeness:.2f}")
        print(f"Average Units Present Score: {avg_units:.2f}")
    else:
        print("No samples for rubric evaluation.")

    print("\n--- Detailed Results ---")
    for i, sample in enumerate(MOCK_SYNTH_DATA):
        print(f'\nSample {i+1} (ID: {sample["id"]}):')
        print(f'  Question: {sample["question"]}')
        print(f'  Answer: {sample["answer"]}')
        print(f"  - Factual Check Result: {evaluate_factual_faithfulness(sample)}")
        print(f"  - Rubric Check Result: {evaluate_rubric_quality(sample)}")

    print("-" * 70)
    print("Evaluation complete.")


if __name__ == "__main__":
    main()
